package com.cts.handson.entity;import jakarta.persistence.*;@Entity @Table(name="country") public class Country{@Id @Column(name="co_code") private String code;@Column(name="co_name") private String name;public Country(){}public Country(String c,String n){code=c;name=n;}public String getCode(){return code;}public String getName(){return name;}public void setCode(String c){code=c;}public void setName(String n){name=n;}public String toString(){return code+" - "+name;}}